import React, { useMemo, useState } from "react";
import { Container, Form, Modal, Row, Col } from "react-bootstrap";
import ProjectCard from "./ProjectCards";
import Particle from "../Particle";
import { projects } from "../../data/projects";
import { useInViewOnce } from "../../hooks/useInViewOnce";

function Projects() {
  const header = useInViewOnce();
  const [query, setQuery] = useState("");
  const [activeId, setActiveId] = useState(null);

  const ordered = useMemo(() => {
    return [...projects].sort((a, b) => {
      const ra = typeof a.rank === "number" ? a.rank : 0;
      const rb = typeof b.rank === "number" ? b.rank : 0;
      if (rb !== ra) return rb - ra;
      return (a.title ?? "").localeCompare(b.title ?? "");
    });
  }, []);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return ordered.filter((p) => {
      const hay = `${p.title} ${p.description} ${p.language} ${(p.tags ?? []).join(" ")}`.toLowerCase();
      const matchesQuery = q.length === 0 || hay.includes(q);
      return matchesQuery;
    });
  }, [ordered, query]);

  const active = useMemo(() => projects.find((p) => p.id === activeId) ?? null, [activeId]);

  return (
    <Container fluid className="project-section">
      <Particle />
      <Container>
        <div
          ref={header.ref}
          className={`projects-header section-card reveal ${header.isInView ? "is-visible" : ""}`}
        >
          <div className="section-header">
            <h1 className="section-title">
              Selected <span className="purple">Projects</span>
            </h1>
            <p className="section-subtitle">
              A curated selection of work — engineering-focused, with an emphasis on clarity and learning.
            </p>
          </div>

          <div className="projects-controls">
            <Form.Control
              className="projects-search"
              placeholder="Search (title, stack, tags)…"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
          </div>

          <div className="projects-meta">
            Showing <span className="purple">{filtered.length}</span> of{" "}
            <span className="purple">{projects.length}</span>
          </div>
        </div>

        <Row style={{ justifyContent: "center", paddingBottom: "10px" }}>
          {filtered.map((project) => (
            <Col key={project.id} md={6} lg={4} className="project-card">
              <div className="reveal is-visible">
                <ProjectCard
                  imgPath={project.image}
                  title={project.title}
                  description={project.description}
                  tags={project.tags}
                  ghLink={project.links?.github}
                  demoLink={project.links?.demo}
                  onOpen={() => setActiveId(project.id)}
                />
              </div>
            </Col>
          ))}
        </Row>

        <Modal show={Boolean(active)} onHide={() => setActiveId(null)} centered contentClassName="skill-modal">
          <Modal.Header closeButton>
            <Modal.Title>{active?.title}</Modal.Title>
          </Modal.Header>
          <Modal.Body>
            <div className="project-modal-tags">
              {(active?.tags ?? []).map((t) => (
                <span key={`modal-${active?.id}-${t}`} className="project-tag">
                  {t}
                </span>
              ))}
            </div>
            <div className="project-modal-stack">{active?.language}</div>
            <div className="project-modal-desc">
              {active?.details
                ? active.details.map((para, i) => <p key={i}>{para}</p>)
                : <p>{active?.description}</p>
              }
            </div>

            {(active?.links?.github || active?.links?.demo) && (
              <div className="project-card-actions">
                {active?.links?.github && (
                  <a className="btn btn-primary project-card-btn" href={active.links.github} target="_blank" rel="noreferrer">
                    GitHub
                  </a>
                )}
                {active?.links?.demo && (
                  <a className="btn btn-outline-primary project-card-btn" href={active.links.demo} target="_blank" rel="noreferrer">
                    Live demo
                  </a>
                )}
              </div>
            )}
          </Modal.Body>
        </Modal>
      </Container>
    </Container>
  );
}

export default Projects;
